/**
 * Phase-14 dataset-version snapshot DDL.
 *
 * One table: `dataset_versions`. Admin freezes the current state of
 * approved annotations into a labeled snapshot; the manifest is a
 * jsonb array of {annotationId, topicId, payload, …} so the snapshot
 * is fully self-contained — no joins needed at read time.
 *
 * Unique (workspace_id, label) — versions are workspace-scoped and
 * labels can't collide. Empty label is auto-generated by the action.
 */

import { config as loadEnv } from 'dotenv'
loadEnv({ path: '.env.local' })
loadEnv({ path: '.env' })

import postgres from 'postgres'

const DATABASE_URL = process.env.DATABASE_URL
if (!DATABASE_URL) {
  // eslint-disable-next-line no-console
  console.error('DATABASE_URL is not set.')
  process.exit(1)
}

const STATEMENTS: Array<{ label: string; sql: string }> = [
  {
    label: 'CREATE TABLE dataset_versions',
    sql: `
      CREATE TABLE IF NOT EXISTS "dataset_versions" (
        "id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),
        "workspace_id" uuid NOT NULL REFERENCES "workspaces"("id"),
        "label" text NOT NULL,
        "description" text,
        "item_count" integer NOT NULL,
        "manifest" jsonb NOT NULL,
        "byte_size" integer NOT NULL,
        "frozen_by" uuid REFERENCES "users"("id"),
        "frozen_at" timestamp NOT NULL DEFAULT now()
      );
    `,
  },
  {
    label: 'UNIQUE INDEX dataset_versions_ws_label_uniq',
    sql: `CREATE UNIQUE INDEX IF NOT EXISTS "dataset_versions_ws_label_uniq" ON "dataset_versions" ("workspace_id", "label");`,
  },
  {
    label: 'INDEX dataset_versions_ws_frozen_idx',
    sql: `CREATE INDEX IF NOT EXISTS "dataset_versions_ws_frozen_idx" ON "dataset_versions" ("workspace_id", "frozen_at" DESC);`,
  },
]

async function main() {
  const sql = postgres(DATABASE_URL!, { max: 1, prepare: false })
  try {
    // eslint-disable-next-line no-console
    console.log(`[apply] connected, running ${STATEMENTS.length} statements`)
    for (const stmt of STATEMENTS) {
      const t0 = Date.now()
      // eslint-disable-next-line no-console
      console.log(`[apply] ${stmt.label} …`)
      await sql.unsafe(stmt.sql)
      // eslint-disable-next-line no-console
      console.log(`[apply] ${stmt.label} ✓ (${Date.now() - t0}ms)`)
    }
    const [check] = await sql<Array<{ exists: boolean }>>`
      SELECT EXISTS (
        SELECT 1 FROM information_schema.tables
        WHERE table_name = 'dataset_versions'
      ) AS exists
    `
    // eslint-disable-next-line no-console
    console.log('[verify]', check)
  } finally {
    await sql.end({ timeout: 5 })
  }
}

main().catch((e) => {
  // eslint-disable-next-line no-console
  console.error('[apply] failed:', e)
  process.exit(1)
})
